arguments.file_text:
@* Displays a single task as a card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftAsync">&larr; Move Left</button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightAsync">Move Right &rarr;</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

