toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <p><em>Loading board...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                ToDo="CountByStatus("To Do")"
                InProgress="CountByStatus("In Progress")"
                DoneCount="CountByStatus("Done")"
                Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredByStatus("To Do")"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="(id) => MoveTaskAsync(id, "In Progress")"
                      OnTaskAdded="(data) => CreateTaskAsync(data, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredByStatus("In Progress")"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="(id) => MoveTaskAsync(id, "To Do")"
                      OnMoveRight="(id) => MoveTaskAsync(id, "Done")"
                      OnTaskAdded="(data) => CreateTaskAsync(data, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredByStatus("Done")"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="(id) => MoveTaskAsync(id, "In Progress")"
                      OnTaskAdded="(data) => CreateTaskAsync(data, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status)
        => allTasks.Count(t => t.Status == status);

    private List<TaskItem> FilteredByStatus(string status)
        => allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(searchText)
                        || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                allTasks[index] = allTasks[index] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTaskAsync(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(created with { Status = status });
            if (status != "To Do")
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, status);
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

